use dear_imgui_rs::{Context, FontConfig, draw_data};
use dear_imgui_wgpu::{GammaMode, WgpuInitInfo, WgpuRenderer};
use dear_imgui_winit::{HiDpiMode, WinitPlatform};
use winit::{event::WindowEvent, window::Window};

use crate::texture::DepthTexture;

pub struct ImGuiRenderer {
    context: Context,
    platform: WinitPlatform,
    renderer: WgpuRenderer,
}

impl ImGuiRenderer {
    pub fn new(device: &wgpu::Device, queue: &wgpu::Queue, surface_format: wgpu::TextureFormat, window: &Window) -> Self {
        let mut context = Context::create();
        context.set_ini_filename(None::<String>).unwrap();

        let font_cfg = FontConfig::new()
            .pixel_snap_h(true)
            .size_pixels(13.0)
            .glyph_offset([0.0, 0.5 * (13.0 / 16.0)]);

        context.fonts().add_font_from_memory_compressed_ttf(
            &PROGGY_FOREVER_MINIMAL_TTF_COMPRESSED_DATA,
            13.0,
            Some(&font_cfg),
            None,
        );

        let mut platform = WinitPlatform::new(&mut context);
        platform.attach_window(window, HiDpiMode::Default, &mut context);

        let init_info = WgpuInitInfo::new(
            device.clone(), 
            queue.clone(), 
            surface_format
        ).with_depth_stencil_format(DepthTexture::DEPTH_FORMAT);

        let mut renderer = WgpuRenderer::new(init_info, &mut context).unwrap();
        renderer.set_gamma_mode(GammaMode::Auto);

        Self {
            context,
            platform,
            renderer,
        }
    }

    pub fn render(&mut self, window: &Window, render_pass: &mut wgpu::RenderPass) {
        self.platform.prepare_frame(window, &mut self.context);
        let ui = self.context.frame();

        ui.window("Hello world").build(|| {
            ui.text("YAYYY?!??!");
            ui.text("Does it work?");
        });

        let draw_data = self.context.render();

        self.renderer.new_frame().unwrap();
        self.renderer.render_draw_data(draw_data, render_pass).unwrap();
    }

    pub fn handle_window_event(&mut self, window: &Window, event: &WindowEvent) {
        self.platform.handle_window_event(&mut self.context, window, event);
    }
}

